using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchive now defaults to UTF-8 (sets
        // the EFS General Purpose Bit Flag). The legacy Java consumer
        // expects Shift-JIS filenames, so we must pass the encoding
        // explicitly to preserve the old behavior.
        var shiftJis = CodePagesEncodingProvider.Instance.GetEncoding("shift_jis")
                       ?? Encoding.UTF8;
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

